ewline&= rac{\mathbf{w}\cdot \mathbf{v}}{\|\mathbf{w}\|} rac{\mathbf{q}\cdot \mathbf{v}}{\|\mathbf{q}\|\cdot\|\mathbf{v}\|}\mathbf{v}
ewline\mathbf{q}&= rac{\mathbf{w}\cdot \mathbf{v}}{\|\mathbf{w}\|} rac{\mathbf{q}\cdot \mathbf{v}}{\|\mathbf{q}\|\cdot\|\mathbf{v}\|}\mathbf{v}
